const TYPE_MAP = {
  'Goal':  'Goal',
  'subst': 'Substitution',
  'Var':   'VideoAssistant'
};

function mapEventType(type, detail) {
  if (type === 'Card') {
    const d = (detail || '').toLowerCase();
    if (d.includes('yellow red') || d.includes('red card')) return 'RedCard';
    if (d.includes('yellow')) return 'YellowCard';
    return 'YellowCard';
  }
  return TYPE_MAP[type] || 'Default';
}

function mapPhase(elapsed) {
  if (!elapsed)       return 'FirstHalf';
  if (elapsed <= 45)  return 'FirstHalf';
  if (elapsed <= 46)  return 'FirstHalfBreak';
  if (elapsed <= 90)  return 'SecondHalf';
  if (elapsed <= 105) return 'ExtraFirstHalf';
  if (elapsed <= 106) return 'ExtraBreak';
  if (elapsed <= 120) return 'ExtraSecondHalf';
  return 'After';
}

const postedIds = new Set(
  ($('Check_Existing_Events').first().json.items || [])
    .map(e => e.sourceId)
);

const matchId   = 1388536;
const fixtureId = '1388536';
const response  = $input.all()[0].json.response || [];

return response
  .map((event, i) => {
    const sourceId = `${fixtureId}-${event.time.elapsed}-${i}`;
    return {
      json: {
        matchId,
        fixtureId,
        sourceId,
        alreadyPosted: postedIds.has(sourceId),
        liveTickerEventType: mapEventType(event.type, event.detail),
        liveTickerPhaseType: mapPhase(event.time.elapsed),
        time:           event.time.elapsed,
        timeAdditional: event.time.extra || 0,
        type:           event.type,
        detail:         event.detail || '',
        playerId:       event.player?.id   || null,
        playerName:     event.player?.name || null,
        assistId:       event.assist?.id   || null,
        assistName:     event.assist?.name || null,
        teamName:       event.team?.name   || null
      }
    };
  })
  .filter(item => !item.json.alreadyPosted);

const llm    = $input.first().json;
const evData = $('Events mappen + Filter3').all()[$itemIndex]?.json || {};
const text = llm.choices?.[0]?.message?.content || null;

const players = [];
if (evData.playerId) players.push({
  playerId:      evData.playerId,
  playerName:    evData.playerName || null,
  avatarImageUrl: null,
  cheerImageUrl:  null,
  cheerVideoUrl:  null
});
if (evData.assistId) players.push({
  playerId:      evData.assistId,
  playerName:    evData.assistName || null,
  avatarImageUrl: null,
  cheerImageUrl:  null,
  cheerVideoUrl:  null
});

return [{
  json: {
    matchId:  evData.matchId,
    sourceId: evData.sourceId,
    body: {
      sourceId:            evData.sourceId,
      sport:               'Football',
      position:            evData.time || 0,
      time:                evData.time || null,
      timeAdditional:      evData.timeAdditional || 0,
      description:         text,
      imageUrl:            null,
      videoUrl:            null,
      pushTitle:           null,
      pushDescription:     null,
      pushImageSrc:        null,
      embedHtml:           null,
      liveTickerPhaseType: evData.liveTickerPhaseType,
      liveTickerEventType: evData.liveTickerEventType,
      players:             players.length ? players : null
    }
  }
}];

